1	function fb = csirs_feedback(carrier, csirs, H_est_full, nVar_all, slotAssign, pmiMode, cqiMode, panelDimensions)
2	%CSIRS_FEEDBACK  CSI feedback (RI/PMI/CQI/Cap) for Approaches B, C, D.
3	%
4	%  Approach B: Full 128-port SVD upper bound (ideal reference)
5	%  Approach C: Rel-19 Type I Single-Panel Mode A (TS 38.214 S5.2.2.2.1a)
6	%  Approach D: Rel-19 Type I Single-Panel Mode B (TS 38.214 S5.2.2.2.1a)
7	%
8	%  CQI for C/D: computed via nr5g.internal.nrCQISelect (L2SM/MIESM,
9	%  BLER threshold 10%, per TS 38.214 S5.2.2.1) — now supports Rel-19.
10	%
11	%  Inputs:
12	%    carrier      - nrCarrierConfig
13	%    csirs        - {1x4} nrCSIRSConfig objects (csirs{1} used for C/D)
14	%    H_est_full   - [K x 28 x nRx x 128] estimated channel
15	%    nVar_all     - [1x4] noise variance per resource
16	%    slotAssign   - [1x4] slot index per resource
17	%    pmiMode      - (optional) 'Subband' (default) or 'Wideband'
18	%    cqiMode      - (optional) 'Wideband' (default) or 'Subband'
19	%                   When 'Subband': fb.cqi_C/D are vectors [1+numSB x 1]
20	%                   Row 1 = wideband CQI, rows 2..end = per-subband CQI
21	%
22	%  Output:
23	%    fb - struct:
24	%           .ri_B,  .cqi_B,  .cap_B,  .W_B
25	%           .ri_C,  .cqi_C,  .cap_C,  .W_C,  .sinrPerRE_C
26	%           .ri_D,  .cqi_D,  .cap_D,  .W_D,  .sinrPerRE_D
27	%         cqi_C/D: wideband scalar (CQIMode='Wideband')
28	%                  or [1+numSB x 1] vector (CQIMode='Subband'),
29	%                  row 1 = wideband, rows 2..end = per-subband
30	%                  Note: Mode D beam is always wideband (spec constraint),
31	%                  but per-subband CQI with that beam is still valid.
32	
33	if nargin < 6 || isempty(pmiMode)
34	    pmiMode = 'Subband';
35	end
36	pmiMode = validatestring(pmiMode, {'Subband','Wideband'});
37	
38	if nargin < 7 || isempty(cqiMode)
39	    cqiMode = 'Wideband';
40	end
41	cqiMode = validatestring(cqiMode, {'Wideband','Subband'});
42	
43	nRxAntennas  = size(H_est_full, 3);
44	nTxAntennas  = size(H_est_full, 4);
45	nResources   = length(csirs);
46	nPortsPerRes = nTxAntennas / nResources;
47	
48	if nargin < 8 || isempty(panelDimensions)
49	    panelDimensions = [1, 16, 4];   % fallback: [Ng, N1=Nh, N2=Nv]
50	end
51	nSymPerSlot  = carrier.SymbolsPerSlot;
52	
53	% ── Wideband channel matrix H_wb [nRx x nTx] ─────────────────────────────
54	H_wb = zeros(nRxAntennas, nTxAntennas);
55	for r = 1:nResources
56	    pS = (r-1)*nPortsPerRes + 1;  pE = r*nPortsPerRes;
57	    sS = slotAssign(r)*nSymPerSlot + 1;
58	    sE = (slotAssign(r)+1)*nSymPerSlot;
59	    H_wb(:, pS:pE) = squeeze(mean(H_est_full(:, sS:sE, :, pS:pE), [1 2]));
60	end
61	
62	nVar_wb = mean(nVar_all);
63	
64	% Broadcast H_wb to [K x L x nRx x nTx] for nrPMIReport / nrCQISelect
65	carrier.NSlot = 0;
66	nSC = carrier.NSizeGrid * 12;
67	H_4d = repmat(reshape(H_wb, 1, 1, nRxAntennas, nTxAntennas), ...
68	              [nSC, carrier.SymbolsPerSlot, 1, 1]);
69	
70	% ── Subband size per TS 38.214 Table 5.2.1.4-2 (smallest valid value) ────
71	nSizeBWP = carrier.NSizeGrid;
72	if nSizeBWP >= 145
73	    subbandSize = 16;
74	elseif nSizeBWP >= 73
75	    subbandSize = 8;
76	elseif nSizeBWP >= 24
77	    subbandSize = 4;
78	else
79	    subbandSize = [];   % BWP < 24 PRBs: no subbands
80	end
81	
82	% ── Shared struct for nrCQISelect (Rel-19, now supported) ────────────────
83	cqiCfg.NSizeBWP        = carrier.NSizeGrid;
84	cqiCfg.NStartBWP       = 0;
85	cqiCfg.CodebookType    = 'typeI-SinglePanel-r19';
86	cqiCfg.PanelDimensions = panelDimensions;
87	cqiCfg.PMIMode         = pmiMode;
88	cqiCfg.SubbandSize     = subbandSize;
89	cqiCfg.CQIMode         = cqiMode;
90	cqiCfg.CQITable        = 'table1';
91	
92	% =========================================================================
93	%  APPROACH B: Full 128-Port SVD Upper Bound
94	%  CQI: ZF SINR per layer → threshold table (wideband SVD, no codebook grid)
95	% =========================================================================
96	[~, S_B, V_B]    = svd(H_wb, 'econ');
97	singVals_B       = diag(S_B);
98	snr_sv_B         = singVals_B.^2 / nVar_wb;
99	riThresh_B       = 0.1 * singVals_B(1);
100	ri_B             = min(sum(singVals_B > riThresh_B), nRxAntennas);
101	W_B              = V_B(:, 1:ri_B);
102	
103	H_eff_B = H_wb * W_B;
104	W_zf_B  = pinv(H_eff_B);
105	sinr_B  = zeros(ri_B, 1);
106	for lyr = 1:ri_B
107	    sig  = abs(W_zf_B(lyr,:) * H_eff_B(:,lyr))^2;
108	    intf = sum(abs(W_zf_B(lyr,:) * H_eff_B).^2) - sig;
109	    nse  = nVar_wb * norm(W_zf_B(lyr,:))^2;
110	    sinr_B(lyr) = sig / (intf + nse);
111	end
112	cqi_tbl = [-6.7,-4.7,-2.3,0.2,2.4,4.7,6.9,9.3,10.7,12.2,14.1,15.6,18.0,20.3,22.7];
113	sinr_B_dB = 10*log10(sinr_B);
114	cqi_B     = max(sum(mean(sinr_B_dB) >= cqi_tbl), 1);   % wideband scalar
115	cap_B     = sum(log2(1 + snr_sv_B(1:ri_B) / ri_B));
116	
117	fb.ri_B   = ri_B;
118	fb.cqi_B  = cqi_B;
119	fb.cap_B  = cap_B;
120	fb.W_B    = W_B;
121	fb.sinr_B = sinr_B;   % [ri_B x 1] per-layer wideband ZF SINR (linear)
122	
123	% =========================================================================
124	%  APPROACH C: Rel-19 Mode A
125	%  RI: nrRISelect with typeI-SinglePanel-r19 (capacity maximisation)
126	%  CQI: nrCQISelect (L2SM/MIESM) — now supports typeI-SinglePanel-r19
127	% =========================================================================
128	riCfg_C.NSizeBWP        = carrier.NSizeGrid;
129	riCfg_C.NStartBWP       = 0;
130	riCfg_C.CodebookType    = 'typeI-SinglePanel-r19';
131	riCfg_C.PanelDimensions = panelDimensions;
132	riCfg_C.CodebookMode    = 1;
133	riCfg_C.PMIMode         = pmiMode;
134	riCfg_C.SubbandSize     = subbandSize;
135	[ri_C, ~, ~] = nr5g.internal.nrRISelect(carrier, csirs{1}, riCfg_C, H_4d, nVar_wb);
136	
137	cqiCfg_C             = cqiCfg;
138	cqiCfg_C.CodebookMode = 1;
139	[cqi_C_vec, ~, ~, pmiInfo_C] = nr5g.internal.nrCQISelect( ...
140	    carrier, csirs{1}, cqiCfg_C, ri_C, H_4d, nVar_wb);
141	% cqi_C_vec: row 1 = wideband, rows 2..end = per-subband (when CQIMode='Subband')
142	if strcmpi(cqiMode, 'Subband')
143	    cqi_C = cqi_C_vec;   % full vector [1+numSB x 1]
144	else
145	    cqi_C = cqi_C_vec(1);
146	end
147	W_C   = pmiInfo_C.W(:,:,1);   % first subband precoder for wideband capacity approx
148	cap_C = real(log2(det(eye(nRxAntennas) + ...
149	    (1/nVar_wb) * (H_wb*W_C*(H_wb*W_C)'))));
150	
151	fb.ri_C        = ri_C;
152	fb.cqi_C       = cqi_C;
153	fb.cap_C       = cap_C;
154	fb.W_C         = W_C;
155	fb.sinrPerRE_C = pmiInfo_C.SINRPerREPMI;
156	
157	% =========================================================================
158	%  APPROACH D: Rel-19 Mode B
159	%  RI: nrRISelect with typeI-SinglePanel-r19 (capacity maximisation)
160	%  CQI: nrCQISelect (L2SM/MIESM) — typeI-SinglePanel-r19
161	% =========================================================================
162	riCfg_D.NSizeBWP        = carrier.NSizeGrid;
163	riCfg_D.NStartBWP       = 0;
164	riCfg_D.CodebookType    = 'typeI-SinglePanel-r19';
165	riCfg_D.PanelDimensions = panelDimensions;
166	riCfg_D.CodebookMode    = 2;
167	riCfg_D.PMIMode         = pmiMode;
168	riCfg_D.SubbandSize     = subbandSize;
169	[ri_D, ~, ~] = nr5g.internal.nrRISelect(carrier, csirs{1}, riCfg_D, H_4d, nVar_wb);
170	
171	cqiCfg_D             = cqiCfg;
172	cqiCfg_D.CodebookMode = 2;
173	% Mode B beam group (i1) is always wideband (spec constraint).
174	% Co-phase (i2) follows pmiMode: 'Subband' activates Phase 2 per-subband
175	% co-phase in nrPMIReport, giving consistent W between RI and CQI steps.
176	cqiCfg_D.PMIMode      = pmiMode;
177	[cqi_D_vec, ~, ~, pmiInfo_D] = nr5g.internal.nrCQISelect( ...
178	    carrier, csirs{1}, cqiCfg_D, ri_D, H_4d, nVar_wb);
179	% cqi_D_vec: row 1 = wideband, rows 2..end = per-subband (when CQIMode='Subband')
180	if strcmpi(cqiMode, 'Subband')
181	    cqi_D = cqi_D_vec;   % full vector [1+numSB x 1]
182	else
183	    cqi_D = cqi_D_vec(1);
184	end
185	W_D   = pmiInfo_D.W(:,:,1);   % first subband precoder for wideband capacity approx
186	cap_D = real(log2(det(eye(nRxAntennas) + ...
187	    (1/nVar_wb) * (H_wb*W_D*(H_wb*W_D)'))));
188	
189	fb.ri_D        = ri_D;
190	fb.cqi_D       = cqi_D;
191	fb.cap_D       = cap_D;
192	fb.W_D         = W_D;
193	fb.sinrPerRE_D = pmiInfo_D.SINRPerREPMI;
194	
195	end
196	

