function tp = computeTP(ri, mcsIdx, mcsTab, nRE_slot, slotDur_s)
    row = mcsIdx + 1;   % mcsIdx is 0-based; MATLAB table is 1-based
    if row < 1 || row > height(mcsTab) || isnan(mcsTab.TargetCodeRate(row))
