narginchk(6,6);

% Validate inputs
numCSIRSPorts = csirs.NumCSIRSPorts(1);
% ThangTQ23_128T128R_Rel19: H is aggregated 128-port — use actual size, not per-resource count
if strcmpi(reportConfig.CodebookType,'typeI-SinglePanel-r19')
    numCSIRSPorts = size(H,4);
end
% ThangTQ23_128T128R_eTypeII_Rel19: H aggregated over K CSI-RS resources (§5.2.2.2.5a)
if strcmpi(reportConfig.CodebookType,'eTypeII-r19')
    numCSIRSPorts = size(H,4);
end
nr5g.internal.validateLayerDependentParams(carrier,reportConfig,numCSIRSPorts,H,nLayers);

% Set the below flags to identify the codebook type
isType1SinglePanel = strcmpi(reportConfig.CodebookType,'Type1SinglePanel');
isType1MultiPanel = strcmpi(reportConfig.CodebookType,'Type1MultiPanel');
isType2 = strcmpi(reportConfig.CodebookType,'Type2');
isEnhType2 = strcmpi(reportConfig.CodebookType,'eType2');
% ThangTQ23_128T128R_Rel19: Refined Type I Single-Panel (TS 38.214 §5.2.2.2.1a)
isType1SinglePanel_r19 = strcmpi(reportConfig.CodebookType,'typeI-SinglePanel-r19');
% ThangTQ23_128T128R_eTypeII_Rel19: Refined eTypeII (TS 38.214 §5.2.2.2.5a)
isRefinedEnhType2 = strcmpi(reportConfig.CodebookType,'eTypeII-r19');
if isType1SinglePanel_r19; isType1SinglePanel = true; end
% modeB all ranks: factored search path (no precomputed codebook)
isModeB_r19 = isType1SinglePanel_r19 && (reportConfig.CodebookMode == 2);

% Get the codebook
[codebook,indexSetSizes] = getCodebook(reportConfig,numCSIRSPorts,nLayers);

% Get the PMI subband related information
subbandInfo = nr5g.internal.getPMISubbandInfo(carrier,reportConfig);

% Get the CSI-RS indices in BWP resource grid and channel matrix
% corresponding to the BWP REs. H is of size
% K-by-L-by-nRxAnts-by-Pcsirs and H_bwp is of size
% nRxAnts-by-Pcsirs-reportConfig.NSizeBWP*12-by-L
csirsIndSubs = nr5g.internal.getCSIRSIndicesForCSI(carrier,csirs);
[H_bwp,csirsIndBWP_k,csirsIndBWP_l,csirsIndBWP_p] = getCSIRSIndicesAndHInBWP(carrier,reportConfig,H,csirsIndSubs);    
if(~isscalar(nVar))
    nVar = getCSIRSIndicesAndHInBWP(carrier,reportConfig,nVar,csirsIndSubs);
end

% Generate PMI set and output information structure with NaNs
[PMINaNSet,nanInfo] = getPMINaNSet(reportConfig,subbandInfo,codebook,indexSetSizes,numCSIRSPorts,nLayers,csirsIndBWP_k);

% Report the outputs as all NaNs, if there are no CSI-RS resources
% present in the BWP, or if all the elements in the channel matrix are
% NaNs, or all the precoding matrices of the type I codebook are
% restricted
if isempty(csirsIndBWP_k) || all(isnan(H_bwp(:))) ||...
    ((isType1SinglePanel || isType1MultiPanel) && (~any(codebook(:))))       
    PMISet = PMINaNSet;
    info = nanInfo;
    return;
end

% Compute PMI
Htemp = reshape(H_bwp,size(H_bwp,1),size(H_bwp,2),[]);
Hcsirs = Htemp(:,:,csirsIndBWP_k+(csirsIndBWP_l-1)*size(H_bwp,3)); % Channel matrices at CSI-RS locations

% Interference plus noise covariance matrices at CSI-RS locations
if(~isscalar(nVar))
    nVarTemp = reshape(nVar,size(nVar,1),size(nVar,2),[]);
    nVarUpdated = nVarTemp(:,:,csirsIndBWP_k+(csirsIndBWP_l-1)*size(nVar,3)); % Covariance matrices at CSI-RS locations
    nVar = nVarUpdated;
end

if isModeB_r19
    % ThangTQ23_128T128R_Rel19 modeB: factored greedy search + per-subband co-phase
    nVar_scalar = mean(nVar(:), 'omitnan');
    [W, pmiModeB, SubbandSINRs] = getPMIType1SinglePanelR19CodebookModeB( ...
        Hcsirs, reportConfig, nLayers, nVar_scalar, numCSIRSPorts, ...
        subbandInfo, csirsIndBWP_k);
    % PMISet: 1-based
    %   i1 = [q1+1, q2+1, n_idx(1)+1, ..., n_idx(v)+1]  (wideband beam)
    %   i2 = c_idx_sb + 1  [nLayers × numSubbands]       (per-subband co-phase)
    PMISet.i1 = [pmiModeB.q1+1, pmiModeB.q2+1, pmiModeB.n_idx+1];
    PMISet.i2 = pmiModeB.c_idx_sb + 1;   % [nLayers × numSubbands]

    % Build SINRPerREPMI [csirsIndLen × nLayers] using per-subband precoders.
    % For each RE, use the precoder of the subband it belongs to.
    nRE = length(csirsIndBWP_k);
    SINRPerREPMI = zeros(nRE, nLayers);
    subbandStart_mb = 0;
    for sb = 1:subbandInfo.NumSubbands
        sbMask = (csirsIndBWP_k > subbandStart_mb*12) & ...
                 (csirsIndBWP_k < (subbandStart_mb + subbandInfo.SubbandSizes(sb))*12 + 1);
        sbIdx = find(sbMask);
        if ~isempty(sbIdx)
            W_sb = W(:,:,sb);   % [Pcsirs × nLayers]
            for k = 1:length(sbIdx)
                sinr_re = nr5g.internal.nrPrecodedSINR( ...
                    Hcsirs(:,:,sbIdx(k)), nVar_scalar, W_sb);
                SINRPerREPMI(sbIdx(k),:) = sinr_re(:).';
            end
        end
        subbandStart_mb = subbandStart_mb + subbandInfo.SubbandSizes(sb);
    end
    SINRPerRE    = [];
    SINRPerREOut = [];
    codebookOut  = [];

elseif isType2 || isEnhType2 || isRefinedEnhType2
    % ThangTQ23_128T128R_eTypeII_Rel19: eTypeII-r19 reuses same wideband engine —
    % getTypeIIPMIWideband is fully parameterized by N1,N2 (no port-count limit).
    [W,PMISet,SubbandSINRs,wbInfo] = getTypeIIPMIWideband(reportConfig,Hcsirs,nLayers,nVar,PMINaNSet);
    if all(isnan(W))
        PMISet = PMINaNSet;
        info = nanInfo;
        return;
    end
    SINRPerRE = computeSINRPerRE(Hcsirs,W,nVar,csirsIndBWP_k,indexSetSizes);
    SINRPerREPMI = SINRPerRE;
else
    SINRPerRE = computeSINRPerRE(Hcsirs,codebook,nVar,csirsIndBWP_k,indexSetSizes);
    [PMISet,W,SINRPerREPMI,SubbandSINRs] = getTypeIPMIWideband(reportConfig,SINRPerRE,codebook,indexSetSizes);
end

% Get the number of subbands
numSubbands = subbandInfo.NumSubbands;
if ~isModeB_r19 && (numSubbands > 1 || (isType2 && reportConfig.SubbandAmplitude))
    if isType2 || isEnhType2 || isRefinedEnhType2
        % ThangTQ23_128T128R_eTypeII_Rel19: same subband engine, W2CompressionEnhancedType2
        % and quantizeW2ForEnhancedType2 are fully parameterized by N1,N2.
        [PMISet,W,SINRPerREPMI,SubbandSINRs] = getTypeIIPMISubband(reportConfig,H_bwp,nVar,nLayers,csirsIndBWP_k,csirsIndBWP_l,PMISet,wbInfo,subbandInfo,indexSetSizes);
    else
        [PMISet,W,SINRPerREPMI,SubbandSINRs] = getTypeIPMISubband(reportConfig,codebook,PMISet,SINRPerRE,subbandInfo,indexSetSizes,csirsIndBWP_k);
    end
end

% Form the output
if isModeB_r19
    % SINRPerREOut and codebookOut already set above
elseif isType1SinglePanel || isType1MultiPanel
    SINRPerREOut = SINRPerRE;
    codebookOut  = codebook;
    SubbandSINRs = reshape(SubbandSINRs,[subbandInfo.NumSubbands,nLayers,indexSetSizes]);
else % Type II
    SINRPerREOut = [];

