% =========================================================================
%  APPROACH E: Refined eTypeII (TS 38.214 §5.2.2.2.5a, Rel-19, 128 ports)
%  Greedy DFT beam selection — O(L×nGrid) vs exhaustive O(C(nGrid,L)).
%  nrPMIReport's exhaustive search OOMs for L≥4 with 128 ports
%  (Precoders array: C(1024,4)×128×4 entries → >5 GB).
%  RI: capacity maximisation across candidate ranks.
%  CQI: wideband ZF SINR → table lookup (same method as Approach B).
%  ThangTQ23_128T128R_eTypeII_Rel19
% =========================================================================

% L and maxRank from ParameterCombination (TS 38.214 Table 5.2.2.2.5-1)
L_tableE  = [2 2 4 4 4 4 6 6];
L_E       = L_tableE(paramCombE);
maxRankE  = min(nRxAntennas, 4);
if paramCombE >= 7
    maxRankE = min(nRxAntennas, 2);   % PC 7/8: pv(v=3,4)="-" → maxRank=2
end

bestCap_E = -Inf;
ri_E = 1;
W_E  = zeros(nTxAntennas, 1);
for rank_E = 1:maxRankE
    W_try = greedyEType2R19Precoder(H_wb, panelDimensions, L_E, rank_E);
    HW_try = H_wb * W_try;
    cap_try = real(log2(det(eye(nRxAntennas) + ...
        (1/nVar_wb) * (HW_try * HW_try'))));
    if cap_try > bestCap_E
        bestCap_E = cap_try;
        ri_E = rank_E;
        W_E  = W_try;
    end
end
cap_E = bestCap_E;

% SINR per layer: ZF receiver on wideband H (same as Approach B)
H_eff_E = H_wb * W_E;
W_zf_E  = pinv(H_eff_E);
sinr_E  = zeros(ri_E, 1);
for lyr = 1:ri_E
    sig  = abs(W_zf_E(lyr,:) * H_eff_E(:,lyr))^2;
    intf = sum(abs(W_zf_E(lyr,:) * H_eff_E).^2) - sig;
    nse  = nVar_wb * norm(W_zf_E(lyr,:))^2;
    sinr_E(lyr) = sig / (intf + nse);
end

% CQI: mean wideband SINR → table lookup (same cqi_tbl as Approach B)
sinr_E_dB = 10*log10(max(sinr_E, 1e-10));
cqi_E = max(sum(mean(sinr_E_dB) >= cqi_tbl), 1);

% sinrPerRE_E: replicate wideband SINR to [nRE × ri_E] for csirs_computeMetrics
sinrPerRE_E = repmat(sinr_E.', carrier.NSizeGrid * 12, 1);

fb.ri_E        = ri_E;
fb.cqi_E       = cqi_E;
fb.cap_E       = cap_E;
fb.W_E         = W_E;
fb.sinrPerRE_E = sinrPerRE_E;

end

% =========================================================================
%  LOCAL HELPER: Greedy DFT beam selection for eTypeII-r19 (128-port safe)
%  ThangTQ23_128T128R_eTypeII_Rel19
% =========================================================================
function W = greedyEType2R19Precoder(H_wb, panelDimensions, L, nLayers)
%GREEDYETYPE2R19PRECODER  eTypeII-r19 precoder via greedy DFT beam selection.
%
%  Implements the dual-pol DFT codebook structure of TS 38.214 §5.2.2.2.5:
%    W = W1 * W2
%  where W1 selects L DFT beams per polarization (greedy matching pursuit)
%  and W2 contains SVD-based combining coefficients.
%
%  This replaces the exhaustive search in nrPMIReport>getTypeIIPMIWideband,
%  which pre-allocates Precoders(nTx,nLayers,C(nGrid,L),q1,q2) and OOMs
%  for L≥4 with 128-port panels (C(1024,4) ≈ 46×10^9 entries).
%
%  Greedy complexity: O(L × N1*O1 × N2*O2) per rank — tractable for any L.
%
%  Inputs:
%    H_wb          - [nRx × 2*N1*N2] wideband channel matrix
%    panelDimensions - [Ng, N1, N2]
%    L             - number of beams (from ParameterCombination table)
%    nLayers       - number of spatial layers (rank)
%
%  Output:
%    W             - [2*N1*N2 × nLayers] unit-column-norm precoder

    N1      = panelDimensions(2);    % e.g. 16 (horizontal)
    N2      = panelDimensions(3);    % e.g.  4 (vertical)
    O1 = 4; O2 = 4;                  % fixed oversampling (§5.2.2.2.5a)
    nPerPol = N1 * N2;               % ports per polarization (e.g. 64)

    % ── Oversampled DFT grid A [nPerPol × O1*N1*O2*N2] ──────────────────
    % Beam u_{n1,n2} = a_{N1,O1}(n1) ⊗ a_{N2,O2}(n2)  (TS 38.214 §5.2.2.2.3)
    k1   = (0:N1-1)';  k2 = (0:N2-1)';
    nGrid = N1*O1 * N2*O2;
    A = zeros(nPerPol, nGrid);
    idx = 0;
    for n1 = 0:N1*O1-1
        a1 = exp(1j*2*pi*n1*k1/(N1*O1)) / sqrt(N1);
        for n2 = 0:N2*O2-1
            idx = idx + 1;
            a2 = exp(1j*2*pi*n2*k2/(N2*O2)) / sqrt(N2);
            A(:, idx) = kron(a1, a2);   % [N1*N2 × 1]
        end
    end

    % ── Greedy matching pursuit — shared beams for both polarizations ─────
    H1 = H_wb(:, 1:nPerPol);           % pol-1  [nRx × nPerPol]
    H2 = H_wb(:, nPerPol+1:end);       % pol-2  [nRx × nPerPol]
    R1 = H1;  R2 = H2;
    B  = zeros(nPerPol, L);            % selected beam vectors
    for l = 1:L
        scores  = sum(abs(R1*A).^2 + abs(R2*A).^2, 1);  % [1 × nGrid]
        [~, best] = max(scores);
        a_sel   = A(:, best);
        B(:, l) = a_sel;
        % Orthogonal deflation: remove the selected beam's contribution
        R1 = R1 - (R1 * a_sel) * a_sel';
        R2 = R2 - (R2 * a_sel) * a_sel';
    end

    % ── W1: dual-pol block-diagonal [2*nPerPol × 2L] ─────────────────────
    W1 = [B, zeros(nPerPol,L); zeros(nPerPol,L), B];

    % ── W2: combining coefficients [2L × nLayers] via projected SVD ──────
    % Project H_wb onto W1 subspace, take top nLayers right singular vectors
    [~, ~, Vp] = svd(H_wb * W1, 'econ');
    W2 = Vp(:, 1:min(nLayers, size(Vp,2)));   % [2L × nLayers]

    % ── W = W1 * W2, normalise each column to unit power ─────────────────
    W = W1 * W2;
    col_norms = sqrt(sum(abs(W).^2, 1));
    col_norms(col_norms < 1e-10) = 1;
    W = W ./ col_norms;
end

