[rxGrid_s0,rxGrid_s1,~,~,~,~]=csirs_txRx(carrier,txGrid_2slots,allCsirsInd,allCsirsSym,channel,10,nRxAntennas);
[H_est_full,nVar_all]=csirs_channelEstimate(carrier,rxGrid_s0,rxGrid_s1,allCsirsInd,allCsirsSym,slotAssign,cdmLengths,nTxAntennas,nRxAntennas);
fprintf('--- PC=5 (L=4, greedy) ---\n');
fb5=csirs_feedback(carrier,csirs,H_est_full,nVar_all,slotAssign,'Subband','Wideband',panelDimensions,5);
fprintf('  ri_E=%d  cqi_E=%d  cap_E=%.4f  W_E:%dx%d\n',fb5.ri_E,fb5.cqi_E,fb5.cap_E,size(fb5.W_E,1),size(fb5.W_E,2));
m5=csirs_computeMetrics(fb5,carrier);
fprintf('  TP(B/C/D/E)=%.1f/%.1f/%.1f/%.1f\n',m5.tp(1),m5.tp(2),m5.tp(3),m5.tp(4));
fprintf('--- PC=1 (L=2, nrPMIReport) ---\n');
fb1=csirs_feedback(carrier,csirs,H_est_full,nVar_all,slotAssign,'Subband','Wideband',panelDimensions,1);
fprintf('  ri_E=%d  cqi_E=%d  cap_E=%.4f\n',fb1.ri_E,fb1.cqi_E,fb1.cap_E);
fprintf('=== DONE ===\n');
" 2>&1

